-- Refresh students from the 20-04-2026 student list.
-- This clears student-owned data and inserts the replacement student dataset.

BEGIN;

ALTER TABLE students ADD COLUMN IF NOT EXISTS class_id INTEGER REFERENCES classes(id) ON DELETE SET NULL;
ALTER TABLE students ADD COLUMN IF NOT EXISTS avatar TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS join_date DATE;
ALTER TABLE students ADD COLUMN IF NOT EXISTS leave_date DATE;
ALTER TABLE students ADD COLUMN IF NOT EXISTS status VARCHAR(50) DEFAULT 'active';
ALTER TABLE students ADD COLUMN IF NOT EXISTS gender VARCHAR(20) DEFAULT 'male';
ALTER TABLE students ADD COLUMN IF NOT EXISTS last_name TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS first_name TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS phone VARCHAR(100) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS nationality TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS religion TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS province TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS ward TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS house_number TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS street TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS hamlet TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS birth_place TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_birth_year VARCHAR(10) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_birth_year VARCHAR(10) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_name TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_birth_date DATE;
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_phone VARCHAR(100) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_email TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_login TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_id_number VARCHAR(50) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS father_occupation TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_name TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_birth_date DATE;
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_phone VARCHAR(100) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_email TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_login TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_id_number VARCHAR(50) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS mother_occupation TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS id_number VARCHAR(50) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS id_issued_place TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS id_issued_date DATE;
ALTER TABLE students ADD COLUMN IF NOT EXISTS area TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS bhyt_number VARCHAR(100) DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS disability_type TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS policy_beneficiary TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS eye_disease TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS guardian_name TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS guardian_occupation TEXT DEFAULT '';
ALTER TABLE students ADD COLUMN IF NOT EXISTS guardian_birth_year VARCHAR(10) DEFAULT '';

CREATE TEMP TABLE imported_students (
  student_id INTEGER PRIMARY KEY, excel_row INTEGER NOT NULL, class_name TEXT NOT NULL, class_level TEXT NOT NULL,
  name TEXT NOT NULL, last_name TEXT NOT NULL, first_name TEXT NOT NULL, grade TEXT NOT NULL, date_of_birth DATE, join_date DATE,
  status TEXT NOT NULL, gender TEXT NOT NULL, phone TEXT NOT NULL, nationality TEXT NOT NULL, province TEXT NOT NULL, ward TEXT NOT NULL,
  house_number TEXT NOT NULL, street TEXT NOT NULL, hamlet TEXT NOT NULL, id_number TEXT NOT NULL, bhyt_number TEXT NOT NULL, id_issued_place TEXT NOT NULL,
  mother_name TEXT NOT NULL, mother_birth_date DATE, mother_phone TEXT NOT NULL, mother_email TEXT NOT NULL, mother_login TEXT NOT NULL, mother_id_number TEXT NOT NULL, mother_occupation TEXT NOT NULL,
  father_name TEXT NOT NULL, father_birth_date DATE, father_phone TEXT NOT NULL, father_email TEXT NOT NULL, father_login TEXT NOT NULL, father_id_number TEXT NOT NULL, father_occupation TEXT NOT NULL
) ON COMMIT DROP;


TRUNCATE TABLE
  discount_policy_students, fee_adjustments, fee_payments, student_attendance, student_class_history,
  student_fee_period_discounts, student_fee_period_items, student_fee_periods, student_service_subscriptions,
  student_service_usage_entries, students
RESTART IDENTITY CASCADE;

SELECT class_name, MAX(class_level), '', NULL
FROM imported_students i
WHERE NOT EXISTS (SELECT 1 FROM classes c WHERE TRIM(c.name) = TRIM(i.class_name))
GROUP BY class_name;

WITH class_lookup AS (SELECT TRIM(name) AS class_name, MIN(id) AS class_id FROM classes GROUP BY TRIM(name))
  id, name, last_name, first_name, grade, email, date_of_birth, class_id, avatar, join_date, status, gender,
  phone, nationality, religion, province, ward, house_number, street, hamlet, birth_place, father_birth_year, mother_birth_year,
  father_name, father_birth_date, father_phone, father_email, father_login, father_id_number, father_occupation,
  mother_name, mother_birth_date, mother_phone, mother_email, mother_login, mother_id_number, mother_occupation,
  id_number, id_issued_place, id_issued_date, area, bhyt_number, disability_type, policy_beneficiary, eye_disease,
  guardian_name, guardian_occupation, guardian_birth_year
)
SELECT
  i.student_id, i.name, i.last_name, i.first_name, i.grade, '', i.date_of_birth, c.class_id, '', i.join_date, i.status, i.gender,
  i.phone, i.nationality, '', i.province, i.ward, i.house_number, i.street, i.hamlet, '', '', '',
  i.father_name, i.father_birth_date, i.father_phone, i.father_email, i.father_login, i.father_id_number, i.father_occupation,
  i.mother_name, i.mother_birth_date, i.mother_phone, i.mother_email, i.mother_login, i.mother_id_number, i.mother_occupation,
  i.id_number, i.id_issued_place, NULL, '', i.bhyt_number, '', '', '', '', '', ''
FROM imported_students i
LEFT JOIN class_lookup c ON c.class_name = TRIM(i.class_name)
ORDER BY i.student_id;

WITH class_lookup AS (SELECT TRIM(name) AS class_name, MIN(id) AS class_id FROM classes GROUP BY TRIM(name))
SELECT i.student_id, NULL, c.class_id, COALESCE(i.join_date, CURRENT_DATE), 'Import Excel row ' || i.excel_row
FROM imported_students i
LEFT JOIN class_lookup c ON c.class_name = TRIM(i.class_name)
ORDER BY i.student_id;

SELECT setval(pg_get_serial_sequence('students', 'id'), COALESCE((SELECT MAX(id) FROM students), 1), (SELECT COUNT(*) > 0 FROM students));
SELECT setval(pg_get_serial_sequence('student_class_history', 'id'), COALESCE((SELECT MAX(id) FROM student_class_history), 1), (SELECT COUNT(*) > 0 FROM student_class_history));

COMMIT;
